css:
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: Arial, sans-serif;
    font-size: 11pt;
    color: #333;
    line-height: 1.6;
    padding: 20px;
}

/* ── Header ── */
.header-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 10px;
}
.header-logo-cell {
    width: 130px;
    vertical-align: middle;
    text-align: left;
}
.header-title-cell {
    vertical-align: middle;
    text-align: center;
}
.header-spacer-cell {
    width: 130px;
}
.logo {
    max-width: 120px;
    max-height: 60px;
}
.doc-title {
    color: #2c3e50;
    font-size: 22pt;
    font-weight: bold;
    margin-bottom: 4px;
}
.doc-id {
    font-size: 12pt;
    color: #555;
}

.separator {
    border: none;
    border-top: 3px solid #2c3e50;
    margin: 16px 0 20px 0;
}

/* ── Section Header ── */
.section-header {
    color: #2c3e50;
    font-size: 13pt;
    font-weight: bold;
    padding-bottom: 6px;
    margin-top: 24px;
    margin-bottom: 14px;
    border-bottom: 2px solid #2c3e50;
}

/* ── Info Grid (2-col via table) ── */
.grid-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 8px;
    margin-bottom: 10px;
}
.info-box {
    border: 1px solid #ddd;
    padding: 10px 12px;
    border-radius: 4px;
    background-color: #f9f9f9;
    vertical-align: top;
    width: 50%;
}
.info-box-full {
    border: 1px solid #ddd;
    padding: 10px 12px;
    border-radius: 4px;
    background-color: #f9f9f9;
    vertical-align: top;
}
.info-label {
    font-weight: bold;
    color: #2c3e50;
    font-size: 10pt;
    display: block;
    margin-bottom: 4px;
}
.info-value {
    color: #444;
    font-size: 11pt;
}

/* ── Text Content Block ── */
.text-block {
    border: 1px solid #ddd;
    padding: 14px;
    background-color: #f9f9f9;
    border-radius: 4px;
    margin-bottom: 16px;
    min-height: 60px;
    font-size: 11pt;
    color: #444;
    white-space: pre-wrap;
}

/* ── Approval Table ── */
.approval-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 12px;
    margin-bottom: 30px;
    font-size: 10pt;
}
.approval-table th {
    background-color: #34495e;
    color: #fff;
    padding: 9px 10px;
    text-align: left;
    border: 1px solid #2c3e50;
    font-size: 10pt;
}
.approval-table td {
    padding: 9px 10px;
    border: 1px solid #ddd;
}
.approval-table tr.even td {
    background-color: #f4f4f4;
}

/* ── Status Badge ── */
.status-badge {
    display: inline-block;
    padding: 3px 12px;
    border-radius: 12px;
    font-size: 10pt;
    font-weight: bold;
    background-color: #e8f4fd;
    color: #1a6fa0;
    border: 1px solid #aad4f0;
}

/* ── Footer ── */
.footer {
    margin-top: 50px;
    padding-top: 14px;
    border-top: 1px solid #ddd;
    text-align: left;
}
.footer-logo {
    max-width: 110px;
    max-height: 55px;
}
